def capture_summary(results: list) -> str:
    oks = 0
    skips = 0
    for r in results:
        if r["status"] == "ok":
            oks += 1
        elif r["status"] == "skip":
            skips += 1
    fails = len(results) - oks - skips
    code = 0 if oks > 0 else 1
    return "ok=" + str(oks) + " skip=" + str(skips) + " fail=" + str(fails) + " exit=" + str(code)

