def keep_files(paths: list) -> list:
    binary = [".png", ".jpg", ".gif", ".wasm", ".zip", ".pyc", ".so"]
    kept = []
    for rel in paths:
        name = rel.rsplit("/", 1)[-1]
        if "__pycache__" in rel or name.startswith("."):
            continue
        ext = "." + name.rsplit(".", 1)[-1].lower() if "." in name else ""
        if ext in binary:
            continue
        kept.append(rel)
    return kept

