    has name: str;
}

def to_follow(feed: dict) -> list {
    users = [UserView(id=p["id"], name=p["name"]) for p in feed["profiles"]];
    blocked = feed["following"] + [feed["me"]];
    return [u.name for u in users if u.id not in blocked];
}

