obj Lcg {
    has seed: int;

    def next01 -> float {
        self.seed = (self.seed * 1103515245 + 12345) % 2147483648;
        return self.seed / 2147483648.0;
    }
}

def lcg_series(spec: dict) -> list {
    gen = Lcg(seed=spec["seed"]);
    return [round(gen.next01(), 4) for _ in range(spec["n"])];
}

