def resolve_hits(world: dict) -> int:
    score = 0
    alive = [True for _ in world["targets"]]
    for b in world["bullets"]:
        if b["life"] <= 0.0:
            continue
        i = 0
        while i < len(world["targets"]):
            t = world["targets"][i]
            if alive[i]:
                dx = b["x"] - t["x"]
                dy = b["y"] - t["y"]
                dz = b["z"] - t["z"]
                if dx * dx + dy * dy + dz * dz < 1.4:
                    alive[i] = False
                    score += 1
                    break
            i += 1
    return score

