def parse_bench(text: str) -> dict:
    marker = "BENCH "
    for line in text.splitlines():
        s = line.strip()
        if not s.startswith(marker):
            continue
        fields = {}
        for part in s[len(marker):].split(";"):
            if "=" not in part:
                continue
            k = part.split("=", 1)[0].strip()
            v = part.split("=", 1)[1].strip()
            fields[k] = int(v) if v.lstrip("-").isdigit() else v
        return fields
    return {}

